// ============================================
// ANALIZAR PARES - VERSIÓN CORREGIDA
// ============================================

const allItems = $input.all();

console.log(`📊 Recibidos ${allItems.length} items para analizar`);

// Estructuras para almacenar datos
const pairsAnalysis = {};
let bestPair = null;
let bestScore = -1;

// Datos globales
let globalAccountData = {};
let globalNews = [];
let globalCalendar = [];
let globalPositions = [];
let globalPendingOrders = [];
let currencyStrength = null;
let globalRates = null;  // NUEVO: Guardar los rates con precios reales

// Procesar cada item
for (const item of allItems) {
    const data = item.json;

    // Extraer noticias globales
    if (data.news && Array.isArray(data.news) && data.news.length > 0) {
        globalNews = data.news;
        console.log(`📰 Noticias: ${globalNews.length} items`);
    }

    // Extraer calendario global
    if (data.calendar && Array.isArray(data.calendar) && data.calendar.length > 0) {
        globalCalendar = data.calendar;
        console.log(`📅 Calendario: ${globalCalendar.length} eventos`);
    }

    // Extraer datos de cuenta
    if (data.balance !== undefined && Object.keys(globalAccountData).length === 0) {
        globalAccountData = {
            balance: data.balance,
            equity: data.equity,
            profit: data.profit,
            free_margin: data.free_margin,
            leverage: data.leverage,
            currency: data.currency
        };
        console.log(`💰 Cuenta: balance ${data.balance}`);
    }

    // Extraer posiciones
    if (Array.isArray(data) && data.length > 0 && data[0].symbol !== undefined) {
        globalPositions = data;
    }
    if (data.positions && Array.isArray(data.positions)) {
        globalPositions = data.positions;
    }

    // Extraer órdenes pendientes
    if (Array.isArray(data) && data.length > 0 && data[0].state === "PLACED") {
        globalPendingOrders = data;
    }
    if (data.pendings && Array.isArray(data.pendings)) {
        globalPendingOrders = data.pendings;
    }
    if (data.id && data.state === "PLACED" && !Array.isArray(data)) {
        globalPendingOrders.push(data);
    }

    // NUEVO: Extraer rates con precios reales
    if (data.rates && data.strength && data.sentiment) {
        currencyStrength = {
            rates: data.rates,
            strength: data.strength,
            sentiment: data.sentiment,
            timestamp: data.timestamp
        };
        globalRates = data.rates;
        console.log(`💪 Fortaleza de divisas cargada`);
        console.log(`   EURUSD: ${data.rates.EURUSD}`);
        console.log(`   GBPUSD: ${data.rates.GBPUSD}`);
        console.log(`   USDJPY: ${data.rates.USDJPY}`);
        console.log(`   USDCHF: ${data.rates.USDCHF}`);
    }
}

// Función para calcular RSI
function calculateRSI(candles, period = 14) {
    if (!candles || candles.length < period + 1) return 50;
    try {
        let gains = 0, losses = 0;
        for (let i = candles.length - period; i < candles.length; i++) {
            if (i === 0) continue;
            const change = (candles[i].close || 0) - (candles[i-1].close || 0);
            if (change >= 0) gains += change;
            else losses -= change;
        }
        if (losses === 0) return 100;
        const rs = gains / losses;
        return Number((100 - (100 / (1 + rs))).toFixed(2));
    } catch (error) { return 50; }
}

// Función para determinar tendencia
function determineTrend(candles) {
    if (!candles || candles.length < 20) return "neutral";
    try {
        const closes20 = candles.slice(-20).map(c => c.close || 0);
        const sma20 = closes20.reduce((a, b) => a + b, 0) / 20;
        const closes50 = candles.slice(-50).map(c => c.close || 0);
        const sma50 = closes50.reduce((a, b) => a + b, 0) / 50;
        if (sma20 > sma50 * 1.002) return "bullish";
        if (sma20 < sma50 * 0.998) return "bearish";
        return "neutral";
    } catch (error) { return "neutral"; }
}

// Función para encontrar soporte/resistencia
function findSupportResistance(candles, currentPrice) {
    if (!candles || candles.length === 0) {
        return { support: currentPrice * 0.995, resistance: currentPrice * 1.005 };
    }
    try {
        const recentCandles = candles.slice(-20);
        const highs = recentCandles.map(c => c.high || c.close || 0);
        const lows = recentCandles.map(c => c.low || c.close || 0);
        let support = Math.min(...lows);
        let resistance = Math.max(...highs);
        if (support === resistance || recentCandles.length === 1) {
            support = currentPrice * 0.995;
            resistance = currentPrice * 1.005;
        }
        return { support, resistance };
    } catch (error) {
        return { support: currentPrice * 0.995, resistance: currentPrice * 1.005 };
    }
}

// ============================================
// PROCESAR CADA PAR DE DIVISAS - VERSIÓN CORREGIDA
// ============================================

// Lista de pares a analizar
const symbols = ["EURUSD", "GBPUSD", "USDJPY", "USDCHF"];

// PRIMERO: Asegurar que tenemos precios reales de globalRates
if (!globalRates) {
    console.log("⚠️ No se encontraron rates, usando valores por defecto actualizados");
    globalRates = {
        EURUSD: 1.1689,
        GBPUSD: 1.3570,  // Precio actual correcto
        USDJPY: 159.88,
        USDCHF: 0.7996
    };
}

console.log("\n💰 PRECIOS REALES (desde rates):");
console.log(`   EURUSD: ${globalRates.EURUSD}`);
console.log(`   GBPUSD: ${globalRates.GBPUSD}`);
console.log(`   USDJPY: ${globalRates.USDJPY}`);
console.log(`   USDCHF: ${globalRates.USDCHF}`);

for (const symbol of symbols) {
    console.log(`\n📊 Procesando par: ${symbol}`);

    // FORZAR el uso del precio desde globalRates (es el más confiable)
    let currentPrice = globalRates[symbol];
    console.log(`   ✅ Usando precio de rates: ${currentPrice}`);

    // Buscar velas para este símbolo (para RSI y tendencia)
    let candlesData = [];
    for (const item of allItems) {
        const data = item.json;
        if (data.symbol === symbol && data.candles) {
            candlesData = data.candles;
            console.log(`   ✅ Velas encontradas: ${candlesData.length} candles`);
            break;
        }
        // También buscar en datos de precio
        if ((data.bid || data.ask) && !candlesData.length) {
            // Si tiene bid/ask pero no symbol explícito, intentar por rango
            const price = data.bid || data.ask;
            if ((symbol === "EURUSD" && price >= 1.05 && price <= 1.20) ||
                (symbol === "GBPUSD" && price >= 1.25 && price <= 1.40) ||
                (symbol === "USDJPY" && price >= 140 && price <= 170) ||
                (symbol === "USDCHF" && price >= 0.85 && price <= 1.00)) {
                candlesData = data.candles || [];
                console.log(`   ✅ Velas encontradas por rango de precio`);
                break;
            }
        }
    }

    // Si no se encontraron velas, usar datos simulados
    if (candlesData.length === 0) {
        console.log(`   ⚠️ No se encontraron velas para ${symbol}, usando datos simulados`);
    }

    // Calcular indicadores técnicos
    const rsi = calculateRSI(candlesData);
    const trend = determineTrend(candlesData);
    const sr = findSupportResistance(candlesData, currentPrice);

    // Ajustar RSI y tendencia basado en la fortaleza de divisas si no hay velas
    let finalRsi = rsi;
    let finalTrend = trend;

    if (candlesData.length === 0 && currencyStrength) {
        // Usar fortaleza de divisas para determinar tendencia
        if (symbol === "EURUSD") {
            if (currencyStrength.strength.EUR === "bullish" && currencyStrength.strength.USD === "bearish") {
                finalTrend = "bullish";
                finalRsi = 65;
            } else if (currencyStrength.strength.EUR === "bearish" && currencyStrength.strength.USD === "bullish") {
                finalTrend = "bearish";
                finalRsi = 35;
            }
        } else if (symbol === "GBPUSD") {
            if (currencyStrength.strength.GBP === "bullish" && currencyStrength.strength.USD === "bearish") {
                finalTrend = "bullish";
                finalRsi = 65;
            } else if (currencyStrength.strength.GBP === "bearish" && currencyStrength.strength.USD === "bullish") {
                finalTrend = "bearish";
                finalRsi = 35;
            }
        }
        console.log(`   📊 Tendencia ajustada por fortaleza: ${finalTrend}, RSI: ${finalRsi}`);
    }

    // Calcular score
    let score = 50; // Base neutral
    if (finalRsi < 35) score += 25;
    if (finalRsi > 65) score += 25;
    if (finalTrend === "bullish") score += 20;
    if (finalTrend === "bearish") score += 20;

    let finalScore = Math.max(0, Math.min(100, score));

    // Filtrar noticias relevantes
    let relevantCurrencies = [];
    if (symbol === "EURUSD") relevantCurrencies = ["EUR", "USD"];
    else if (symbol === "GBPUSD") relevantCurrencies = ["GBP", "USD"];
    else if (symbol === "USDJPY") relevantCurrencies = ["USD", "JPY"];
    else if (symbol === "USDCHF") relevantCurrencies = ["USD", "CHF"];

    const relevantNews = globalNews.filter(news => 
        news.currency && relevantCurrencies.includes(news.currency)
    );

    const relevantEvents = globalCalendar.filter(event => 
        event.currency && relevantCurrencies.includes(event.currency)
    );

    const highImpactEvents = relevantEvents.filter(e => e.impact === "high");

    // Filtrar posiciones y pendientes del símbolo
    const symbolPositions = globalPositions.filter(p => p.symbol === symbol);
    const symbolPendingOrders = globalPendingOrders.filter(p => p.symbol === symbol);

    // Almacenar análisis
    pairsAnalysis[symbol] = {
        symbol: symbol,
        score: finalScore,
        technical: {
            current_price: currentPrice,  // ← AHORA USA EL PRECIO CORRECTO
            rsi: finalRsi,
            trend: finalTrend,
            support: sr.support,
            resistance: sr.resistance
        },
        fundamental: {
            news_count: relevantNews.length,
            high_impact_events: highImpactEvents.length,
            events: highImpactEvents.map(e => e.event).slice(0, 3),
            relevant_news: relevantNews.slice(0, 5),
            calendar_events: relevantEvents.slice(0, 5)
        },
        positions: {
            count: symbolPositions.length,
            exposure: symbolPositions.reduce((sum, p) => sum + Math.abs(p.volume || 0), 0),
            details: symbolPositions
        },
        pending_orders: {
            count: symbolPendingOrders.length,
            exposure: symbolPendingOrders.reduce((sum, p) => sum + Math.abs(p.volume || 0), 0),
            details: symbolPendingOrders
        }
    };

    console.log(`   ✅ Score: ${finalScore} | RSI: ${finalRsi} | Trend: ${finalTrend} | Price: ${currentPrice}`);

    if (finalScore > bestScore) {
        bestScore = finalScore;
        bestPair = symbol;
    }
}

// Si no se encontró ningún par, usar EURUSD por defecto
if (bestPair === null) {
    bestPair = "EURUSD";
    bestScore = 50;
    console.log("⚠️ No se encontraron pares, usando EURUSD por defecto");
}

const bestAnalysis = pairsAnalysis[bestPair];

// Calcular riesgo
const accountBalance = globalAccountData.balance || 100000;
const totalPositionsExposure = globalPositions.reduce((sum, p) => sum + Math.abs(p.volume || 0), 0);
const totalPendingExposure = globalPendingOrders.reduce((sum, p) => sum + Math.abs(p.volume || 0), 0);

const riskAmount = accountBalance * 0.02;
const stopLossPips = 50;
const pipValue = 10;
let recommendedVolume = riskAmount / (stopLossPips * pipValue);
recommendedVolume = Math.min(recommendedVolume, 0.5);
recommendedVolume = Math.max(recommendedVolume, 0.01);
recommendedVolume = Math.round(recommendedVolume * 100) / 100;

const promptText = `Best Pair: ${bestPair}, Score: ${bestScore}, Price: ${bestAnalysis?.technical?.current_price || 0}, RSI: ${bestAnalysis?.technical?.rsi || 50}`;

console.log("\n========================================");
console.log("🏆 MEJOR PAR:", bestPair);
console.log(`   Score: ${bestScore}`);
console.log(`   Precio: ${bestAnalysis?.technical?.current_price}`);
console.log(`   RSI: ${bestAnalysis?.technical?.rsi}`);
console.log(`   Tendencia: ${bestAnalysis?.technical?.trend}`);
console.log("========================================");

// Resultado final
const result = {
    json: {
        best_pair: bestPair,
        best_score: bestScore,
        all_pairs: pairsAnalysis,
        currency_strength: currencyStrength || {
            rates: globalRates || {},
            strength: { EUR: "neutral", USD: "neutral", GBP: "neutral", JPY: "neutral", CHF: "neutral" },
            sentiment: { score: 0, overall: "neutral", market_mood: "calm" }
        },
        technical: bestAnalysis?.technical || {
            current_price: 0,
            rsi: 50,
            trend: "neutral",
            support: 0,
            resistance: 0
        },
        fundamental: bestAnalysis?.fundamental || {
            news_count: 0,
            high_impact_events: 0,
            events: [],
            relevant_news: [],
            calendar_events: []
        },
        positions: {
            count: globalPositions.length,
            exposure: totalPositionsExposure,
            details: globalPositions
        },
        pending_orders: {
            count: globalPendingOrders.length,
            exposure: totalPendingExposure,
            details: globalPendingOrders
        },
        risk: {
            account_balance: accountBalance,
            risk_amount: riskAmount,
            recommended_volume: recommendedVolume,
            current_exposure: totalPositionsExposure,
            pending_exposure: totalPendingExposure
        },
        global_news: globalNews.slice(0, 5),
        global_calendar: globalCalendar.slice(0, 5),
        prompt_text: promptText,
        timestamp: new Date().toISOString()
    }
};

return [result];

// ============================================
// MEMORY MANAGER - Versión con Aprendizaje
// ============================================

const marketData = $input.all()[0].json;

// Inicializar estructura de memoria si no existe
if (!global.tradingMemory) {
    global.tradingMemory = {
        // Historial
        last_analysis: {},
        recent_decisions: [],
        trades: [],

        // Pesos de agentes (aprendizaje)
        agent_weights: {
            technical: 0.35,
            fundamental: 0.25,
            sentiment: 0.25,
            statistical: 0.15
        },

        // Rendimiento histórico por agente
        performance: {
            technical: { wins: 0, losses: 0, total: 0, winrate: 0, last_confidence: [] },
            fundamental: { wins: 0, losses: 0, total: 0, winrate: 0, last_confidence: [] },
            sentiment: { wins: 0, losses: 0, total: 0, winrate: 0, last_confidence: [] },
            statistical: { wins: 0, losses: 0, total: 0, winrate: 0, last_confidence: [] }
        },

        // Métricas globales
        global_metrics: {
            total_trades: 0,
            winning_trades: 0,
            losing_trades: 0,
            total_pips: 0,
            avg_confidence: 0,
            sharpe_ratio: 0
        },

        // Preferencias ajustables dinámicamente
        preferences: {
            risk_tolerance: 0.02,
            max_positions: 3,
            max_volume: 0.5,
            min_confidence: 45
        },

        // Última actualización
        last_update: new Date().toISOString(),

        // Historial de ajustes de pesos
        weight_history: []
    };
}

// Calcular métricas derivadas si hay trades
if (global.tradingMemory.trades.length > 0) {
    const lastTrades = global.tradingMemory.trades.slice(-20);
    const wins = lastTrades.filter(t => t.order?.status === "executed" && t.result === "win").length;
    const losses = lastTrades.filter(t => t.order?.status === "executed" && t.result === "loss").length;

    // Actualizar winrate global
    if (wins + losses > 0) {
        global.tradingMemory.global_metrics.winning_trades = wins;
        global.tradingMemory.global_metrics.losing_trades = losses;
        global.tradingMemory.global_metrics.total_trades = wins + losses;
    }
}

// Ajustar umbral de confianza según rendimiento
const totalTrades = global.tradingMemory.global_metrics.total_trades;
const winrate = totalTrades > 0 ? 
    (global.tradingMemory.global_metrics.winning_trades / totalTrades) * 100 : 50;

// Si el winrate es alto (>60%), podemos bajar el umbral de confianza
if (winrate > 60 && global.tradingMemory.preferences.min_confidence > 40) {
    global.tradingMemory.preferences.min_confidence = Math.max(40, global.tradingMemory.preferences.min_confidence - 2);
    console.log(`📈 Winrate alto (${winrate.toFixed(1)}%), bajando umbral confianza a ${global.tradingMemory.preferences.min_confidence}%`);
}
// Si el winrate es bajo (<45%), subir el umbral
else if (winrate < 45 && winrate > 0 && global.tradingMemory.preferences.min_confidence < 55) {
    global.tradingMemory.preferences.min_confidence = Math.min(55, global.tradingMemory.preferences.min_confidence + 2);
    console.log(`📉 Winrate bajo (${winrate.toFixed(1)}%), subiendo umbral confianza a ${global.tradingMemory.preferences.min_confidence}%`);
}

// Preparar contexto para los agentes
const context = {
    timestamp: new Date().toISOString(),
    market_data: marketData,
    memory: global.tradingMemory,
    recent_decisions: global.tradingMemory.recent_decisions.slice(-10),
    recent_trades: global.tradingMemory.trades.slice(-5),
    agent_performance: global.tradingMemory.performance,
    global_metrics: global.tradingMemory.global_metrics,
    preferences: global.tradingMemory.preferences
};

console.log("📚 Memory Manager: Contexto cargado con aprendizaje");
console.log(`   - Mejor par: ${marketData.best_pair}`);
console.log(`   - Score: ${marketData.best_score}`);
console.log(`   - Decisiones recientes: ${context.recent_decisions.length}`);
console.log(`   - Trades totales: ${global.tradingMemory.global_metrics.total_trades}`);
console.log(`   - Winrate: ${winrate.toFixed(1)}%`);
console.log(`   - Umbral confianza: ${global.tradingMemory.preferences.min_confidence}%`);
console.log(`   - Pesos agentes: T:${global.tradingMemory.agent_weights.technical.toFixed(2)} F:${global.tradingMemory.agent_weights.fundamental.toFixed(2)} S:${global.tradingMemory.agent_weights.sentiment.toFixed(2)} E:${global.tradingMemory.agent_weights.statistical.toFixed(2)}`);

return [{
    json: context
}];

// ============================================
// PREPARAR ORDEN - Con validación
// ============================================

const decision = $input.all()[0].json;
const marketData = $node["Memory Manager"].json.market_data;

if (decision.decision === "esperar" || decision.decision === "hold") {
    console.log("⏸️ Decisión: ESPERAR/HOLD - No se ejecuta orden");
    return [{
        json: {
            should_execute: false,
            reason: "Decision is HOLD"
        }
    }];
}

// Determinar tipo de orden
let orderType = "BUY";
if (decision.decision === "vender" || decision.decision === "sell") {
    orderType = "SELL";
}

let entryPrice = decision.entrada?.precio || marketData.technical?.current_price || 0;
let stopLoss = decision.stop_loss?.precio || 0;
let takeProfit = decision.take_profit?.objetivo1 || 0;
let volume = decision.volumen || marketData.risk?.recommended_volume || 0.25;

// ============================================
// VALIDAR QUE NO EXISTA ORDEN DUPLICADA
// ============================================

const pendingOrders = marketData.pending_orders?.details || [];
const symbol = marketData.best_pair || "EURUSD";

const existingOrder = pendingOrders.find(order => 
    order.symbol === symbol && 
    Math.abs(parseFloat(order.open) - entryPrice) < 0.0001
);

if (existingOrder) {
    console.log(`⚠️ Orden duplicada evitada: ${orderType} ${symbol} @ ${entryPrice}`);
    return [{
        json: {
            should_execute: false,
            reason: "Duplicate order at same price",
            existing_order_id: existingOrder.id
        }
    }];
}

// ============================================
// CALCULAR STOP LOSS Y TAKE PROFIT
// ============================================

if (stopLoss === 0) {
    const stopDistance = 0.003;
    stopLoss = orderType === "BUY" ? entryPrice - stopDistance : entryPrice + stopDistance;
}

if (takeProfit === 0) {
    const tpDistance = 0.005;
    takeProfit = orderType === "BUY" ? entryPrice + tpDistance : entryPrice - tpDistance;
}

// Validar stop loss
if ((orderType === "SELL" && stopLoss <= entryPrice) || 
    (orderType === "BUY" && stopLoss >= entryPrice)) {
    stopLoss = orderType === "SELL" ? entryPrice + 0.003 : entryPrice - 0.003;
}

// Limitar volumen
const MAX_VOLUME = 0.5;
const MIN_VOLUME = 0.01;
volume = Math.min(volume, MAX_VOLUME);
volume = Math.max(volume, MIN_VOLUME);
volume = Math.round(volume * 100) / 100;

// Redondear precios
entryPrice = Math.round(entryPrice * 100000) / 100000;
stopLoss = Math.round(stopLoss * 100000) / 100000;
takeProfit = Math.round(takeProfit * 100000) / 100000;

console.log("🚀 Orden preparada:", orderType, volume, "lotes @", entryPrice);

return [{
    json: {
        should_execute: true,
        symbol: symbol,
        volume: volume.toString(),
        type: orderType,
        price: entryPrice.toString(),
        stop_loss: stopLoss.toString(),
        take_profit: takeProfit.toString(),
        decision: decision.decision,
        confidence: decision.confianza,
        reasoning: decision.razonamiento
    }
}];

// ============================================
// LOG RESULTADO Y ACTUALIZAR MEMORIA
// ============================================

const orderResult = $input.all()[0].json;

// Intentar obtener datos de diferentes fuentes
let decision = {};
let orderData = {};

// Buscar datos de decisión (puede venir de diferentes nodos)
try {
    // Intentar desde Agente Estratega
    if ($node["Agente Estratega"] && $node["Agente Estratega"].json) {
        decision = $node["Agente Estratega"].json;
        console.log("✅ Datos de decisión desde Agente Estratega");
    }
    // Intentar desde Parse Estratega (si existe)
    else if ($node["Parse Estratega"] && $node["Parse Estratega"].json) {
        decision = $node["Parse Estratega"].json;
        console.log("✅ Datos de decisión desde Parse Estratega");
    }
    // Usar datos del input
    else if (orderResult.decision) {
        decision = orderResult;
        console.log("✅ Datos de decisión desde input");
    }
} catch(e) {
    console.log("⚠️ No se encontraron datos de decisión:", e.message);
}

// Buscar datos de la orden
try {
    if ($node["Preparar Orden"] && $node["Preparar Orden"].json) {
        orderData = $node["Preparar Orden"].json;
        console.log("✅ Datos de orden desde Preparar Orden");
    }
} catch(e) {
    console.log("⚠️ No se encontraron datos de orden:", e.message);
}

// Verificar si la orden se ejecutó correctamente
const orderSuccess = orderResult.error === false || orderResult.success !== false;
const orderId = orderResult.data?.[2] || orderResult.order_id || orderResult.id || null;

// Extraer información de la respuesta de MT5
let orderPrice = orderData?.price || 0;
let orderVolume = orderData?.volume || 0;
let orderType = orderData?.type || "unknown";

// Si hay datos en el array de respuesta
if (orderResult.data && Array.isArray(orderResult.data) && orderResult.data[10]) {
    const orderDetails = orderResult.data[10];
    if (orderDetails[3]) orderType = orderDetails[3];
    if (orderDetails[4]) orderVolume = orderDetails[4];
    if (orderDetails[5]) orderPrice = orderDetails[5];
}

// Log entry
const logEntry = {
    timestamp: new Date().toISOString(),
    decision: decision.decision || orderResult.decision || "unknown",
    confidence: decision.confianza || orderResult.confianza || 0,
    reasoning: decision.razonamiento || orderResult.razonamiento || "",
    convergence: decision.convergence || orderResult.convergence || {},
    order: {
        symbol: orderData?.symbol || orderResult.symbol || "USDJPY",
        volume: orderVolume,
        type: orderType,
        price: orderPrice,
        stop_loss: orderData?.stop_loss || orderResult.stop_loss || 0,
        take_profit: orderData?.take_profit || orderResult.take_profit || 0,
        status: orderSuccess ? "executed" : "failed",
        order_id: orderId,
        message: orderResult.message || ""
    },
    agents: decision.agents_analysis || {},
    weights_used: decision.weights_used || {}
};

// Guardar en memoria global
if (typeof global !== 'undefined') {
    if (!global.tradingMemory) {
        global.tradingMemory = {
            trades: [],
            recent_decisions: [],
            global_metrics: { total_trades: 0, winning_trades: 0, losing_trades: 0 }
        };
    }

