// Función para parsear fechas de MT5 (formato: "2026.04.08 16:21:06")
function parseMT5Date(dateString) {
    if (!dateString) {
        console.log("   ❌ Fecha vacía o null");
        return null;
    }

    console.log(`   Intentando parsear: "${dateString}"`);

    // Formato MT5: "2026.04.08 16:21:06"
    const mt5Match = dateString.match(/(\d{4})\.(\d{2})\.(\d{2})\s+(\d{2}):(\d{2}):(\d{2})/);
    if (mt5Match) {
        const year = parseInt(mt5Match[1]);
        const month = parseInt(mt5Match[2]) - 1;
        const day = parseInt(mt5Match[3]);
        const hour = parseInt(mt5Match[4]);
        const minute = parseInt(mt5Match[5]);
        const second = parseInt(mt5Match[6]);
        const date = new Date(year, month, day, hour, minute, second);
        console.log(`   ✅ Parseado MT5: ${date.toISOString()}`);
        return date;
    }

    // Formato ISO: "2026-04-08T16:21:06Z"
    const isoDate = new Date(dateString);
    if (!isNaN(isoDate.getTime())) {
        console.log(`   ✅ Parseado ISO: ${isoDate.toISOString()}`);
        return isoDate;
    }

    console.log(`   ❌ No se pudo parsear la fecha`);
    return null;
}

